int tlCompositeDrawableEffectChunk16::sortPriority = -1;

tlCompositeDrawableEffectChunk16::tlCompositeDrawableEffectChunk16()
{
    Init();
}

tlCompositeDrawableEffectChunk16::tlCompositeDrawableEffectChunk16(const tlCompositeDrawableEffectChunk16& ch)
{
    Init();
    *this = ch;
}

tlCompositeDrawableEffectChunk16::~tlCompositeDrawableEffectChunk16()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlCompositeDrawableEffectChunk16::tlCompositeDrawableEffectChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_COMPOSITE_DRAWABLE_EFFECT);
    ident = P3D_COMPOSITE_DRAWABLE_EFFECT;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    istranslucent = f->GetLong();
    skeletonjointid = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_COMPOSITE_DRAWABLE_EFFECT);
    }
}

void
tlCompositeDrawableEffectChunk16::Init()
{
    ident = P3D_COMPOSITE_DRAWABLE_EFFECT;
    name = NULL;
    istranslucent = 0;
    skeletonjointid = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_COMPOSITE_DRAWABLE_EFFECT);
    }
}

