tlCompositeDrawableEffectChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( istranslucent );
    s += sizeof( skeletonjointid );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlCompositeDrawableEffectChunk16&
tlCompositeDrawableEffectChunk16::operator=(const tlCompositeDrawableEffectChunk16& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    istranslucent = a.istranslucent;
    skeletonjointid = a.skeletonjointid;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlCompositeDrawableEffectChunk16::operator==(const tlDataChunk& a)
{

    const tlCompositeDrawableEffectChunk16* aptr = dynamic_cast<const tlCompositeDrawableEffectChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(istranslucent == aptr->istranslucent))
    {
        return false;
    }
    if(!(skeletonjointid == aptr->skeletonjointid))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

